class Solution:
    def replaceValueInTree(self, root):
        if root is None:
            return None
        info = {}
        def dfs(node, depth, parent):
            if node is None:
                return
            info[id(node)] = (depth, parent)
            dfs(node.left, depth + 1, node)
            dfs(node.right, depth + 1, node)
        dfs(root, 0, None)
        from collections import defaultdict
        level_sum = defaultdict(int)
        parent_children_sum = defaultdict(int)
        stack = [root]
        while stack:
            node = stack.pop()
            d, p = info[id(node)]
            level_sum[d] += node.val
            if p is not None:
                parent_children_sum[id(p)] += node.val
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        new_vals = {}
        stack = [root]
        while stack:
            node = stack.pop()
            d, p = info[id(node)]
            if p is None:
                new_vals[id(node)] = 0
            else:
                new_vals[id(node)] = level_sum[d] - parent_children_sum[id(p)]
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        stack = [root]
        while stack:
            node = stack.pop()
            node.val = new_vals[id(node)]
            if node.left:
                stack.append(node.left)
            if node.right:
                stack.append(node.right)
        return root

