class Solution:
    def replaceValueInTree(self, root):
        if root is None:
            return None
        root.val = 0
        level = [root]
        while level:
            next_level = []
            child_sums = []
            for node in level:
                cs = (node.left.val if node.left else 0) + (node.right.val if node.right else 0)
                child_sums.append(cs)
                if node.left:
                    next_level.append(node.left)
                if node.right:
                    next_level.append(node.right)
            total_next = sum(child.val for child in next_level)
            for node, cs in zip(level, child_sums):
                new_val = total_next - cs
                if node.left:
                    node.left.val = new_val
                if node.right:
                    node.right.val = new_val
            level = next_level
        return root

