var replaceValueInTree = function(root) {
    if (!root) return null;
    root.val = 0;
    let level = [root];
    while (level.length) {
        const nextLevel = [];
        const childSums = [];
        for (const node of level) {
            const cs = (node.left ? node.left.val : 0) + (node.right ? node.right.val : 0);
            childSums.push(cs);
            if (node.left) nextLevel.push(node.left);
            if (node.right) nextLevel.push(node.right);
        }
        let totalNext = 0;
        for (const child of nextLevel) totalNext += child.val;
        for (let i = 0; i < level.length; i++) {
            const node = level[i];
            const newVal = totalNext - childSums[i];
            if (node.left) node.left.val = newVal;
            if (node.right) node.right.val = newVal;
        }
        level = nextLevel;
    }
    return root;
};
